-- Create "report_workflow_schedules" table
CREATE TABLE "report_workflow_schedules" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "name" character varying NOT NULL,
  "report_workflow_policy_id" bigint NOT NULL,
  "temporal_schedule_id" character varying NOT NULL,
  "interval_ns" bigint NOT NULL,
  "offset_ns" bigint NOT NULL,
  "replay_window_ns" bigint NOT NULL,
  "replay_delay_ns" bigint NOT NULL,
  "replay_limit" bigint NOT NULL,
  "catchup_window_ns" bigint NOT NULL,
  "enabled" boolean NOT NULL DEFAULT false,
  "enabled_at" timestamptz NULL,
  "disabled_at" timestamptz NULL,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  PRIMARY KEY ("id")
);
-- Create index "report_workflow_schedules_name_key" to table: "report_workflow_schedules"
CREATE UNIQUE INDEX "report_workflow_schedules_name_key" ON "report_workflow_schedules" ("name");
-- Create index "report_workflow_schedules_temporal_schedule_id_key" to table: "report_workflow_schedules"
CREATE UNIQUE INDEX "report_workflow_schedules_temporal_schedule_id_key" ON "report_workflow_schedules" ("temporal_schedule_id");
-- Create index "reportworkflowschedule_enabled_updated_at" to table: "report_workflow_schedules"
CREATE INDEX "reportworkflowschedule_enabled_updated_at" ON "report_workflow_schedules" ("enabled", "updated_at");
-- Create index "reportworkflowschedule_report_workflow_policy_id_enabled" to table: "report_workflow_schedules"
CREATE INDEX "reportworkflowschedule_report_workflow_policy_id_enabled" ON "report_workflow_schedules" ("report_workflow_policy_id", "enabled");
